// Static navigation pages from jena-digital.de
const navUrls = [
  'https://jena-digital.de/',
  'https://jena-digital.de/ueber-uns',
  'https://jena-digital.de/ueber-uns/unsere-mitglieder',
  'https://jena-digital.de/ueber-uns/netzwerk-foerderung',
  'https://jena-digital.de/unser-oekosystem-1',
  'https://jena-digital.de/vernetzung',
  'https://jena-digital.de/veranstaltungen',
  'https://jena-digital.de/mitglied-werden',
];

// Discover article URLs from the news listing HTML
const html = $json.data || '';
const articlePattern = /href="(\/ueber-uns\/aktuelles\/detail\/[^"?#]+)"/g;
const discovered = new Set();
let m;
while ((m = articlePattern.exec(html)) !== null) {
  discovered.add('https://jena-digital.de' + m[1]);
}

const allUrls = [...navUrls, ...discovered];
console.log(`Total URLs to scrape: ${allUrls.length} (${navUrls.length} nav + ${discovered.size} articles)`);

return allUrls.map(url => ({ json: { url } }));

// ── HTML cleaning ────────────────────────────────────────────────
function cleanHtml(html) {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

function extractTitle(html) {
  const m = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  return m ? m[1].replace(/ [-|] Jena Digital.*$/i, '').trim() : '';
}

function extractDate(text) {
  const m = text.match(/\b(\d{1,2}\.\d{1,2}\.\d{4})\b/);
  return m ? m[1] : null;
}

// ── Chunking ──────────────────────────────────────────────────────
function chunkText(text, wordsPerChunk = 200, overlap = 30) {
  const words = text.split(/\s+/).filter(w => w.length > 0);
  const chunks = [];
  for (let i = 0; i < words.length; i += wordsPerChunk - overlap) {
    const slice = words.slice(i, i + wordsPerChunk).join(' ');
    if (slice.split(/\s+/).length >= 20) {
      chunks.push(slice);
    }
  }
  return chunks;
}

// ── Process this page ────────────────────────────────────────────
const url = $json.url;
const html = $json.data || '';
const title = extractTitle(html);
const text = cleanHtml(html);
const date = extractDate(text);

// Classify doc type (mirrors Python rag_processor logic)
let doc_type = 'org_page';
if (url.includes('/aktuelles/detail/')) doc_type = 'news_article';
else if (url.includes('/veranstaltungen')) doc_type = 'event';
else if (url.includes('mitglied-werden') || url.includes('satzung')) doc_type = 'legal_doc';

const chunks = chunkText(text);

return chunks.map((chunk, idx) => ({
  json: {
    text: chunk,
    metadata: {
      source: url,
      site: 'jena-digital.de',
      title,
      date,
      doc_type,
      chunk_index: idx,
      total_chunks: chunks.length
    }
  }
}));

const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');

// All chunks are in $json.data as an array of objects
const chunks = $json.data;

const filename = 'jena_digital_scraped.jsonl';

// Build a deterministic hash from all chunk texts combined
const combined = chunks.map(c => c.text).join('\n');
const file_hash = crypto.createHash('sha256').update(combined).digest('hex');

// Format payload for the Record Manager webhook
const payload = {
  filename,
  file_hash,
  chunks: chunks.map(c => ({
    id: crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2),
    text: c.text,
    metadata: c.metadata
  }))
};

console.log(`Sending ${payload.chunks.length} chunks to Record Manager (hash: ${file_hash.slice(0,8)}...)`);

return [{ json: payload }];
